import{_ as e,o as l,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日誌 — 2026-04-30（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/2026-04-30.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/2026-04-30.md"}'),a={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/2026-04-30.md"};function i(s,t,o,d,g,c){return l(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="🫘-黃豆追蹤日誌-—-2026-04-30-週四" tabindex="-1">🫘 黃豆追蹤日誌 — 2026-04-30（週四） <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-2026-04-30-週四" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 2026-04-30（週四）&quot;">​</a></h1><blockquote><p>掃描時間：夜間工作指令執行（第 2 輪更新） 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="📋-8-項追蹤指標檢查結果" tabindex="-1">📋 8 項追蹤指標檢查結果 <a class="header-anchor" href="#📋-8-項追蹤指標檢查結果" aria-label="Permalink to &quot;📋 8 項追蹤指標檢查結果&quot;">​</a></h2><h3 id="✅-指標-1-usda-種植進度報告" tabindex="-1">✅ 指標 1：USDA 種植進度報告 <a class="header-anchor" href="#✅-指標-1-usda-種植進度報告" aria-label="Permalink to &quot;✅ 指標 1：USDA 種植進度報告&quot;">​</a></h3><p><strong>狀態：有重大變化 ⚠️</strong></p><ul><li>3/31 Prospective Plantings 報告：2026 年黃豆種植面積預估 <strong>8,470 萬英畝</strong>，較去年增加 4%</li><li>截至 4/27：已種植 <strong>23%</strong>，較五年平均（12%）快 <strong>11 個百分點</strong></li><li>玉米種植面積減少 3%（9,530 萬英畝），黃豆與棉花面積增加 → 「黃豆傾斜」趨勢明確</li><li>18 個主要黃豆州（占 96% 面積）種植報告自 4/13 開始</li></ul><h3 id="✅-指標-2-巴西供應-收割-出口-豐收" tabindex="-1">✅ 指標 2：巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#✅-指標-2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;✅ 指標 2：巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><p><strong>狀態：有重大變化 ⚠️</strong></p><ul><li>2025/26 賽季巴西黃豆產量預估 <strong>1.778-1.79 億噸</strong>，創歷史紀錄</li><li>2026 年巴西黃豆出口預估創紀錄 <strong>1.136 億噸</strong></li><li>4 月巴西黃豆出口預估 <strong>1,587-1,640 萬噸</strong>（ANEC），較去年 4 月 1,350 萬噸大幅增加</li><li>豐收導致全球價格承壓，巴西出口收入反而可能減少</li></ul><h3 id="✅-指標-3-尿素價格-多單訊號" tabindex="-1">✅ 指標 3：尿素價格 + 多單訊號 <a class="header-anchor" href="#✅-指標-3-尿素價格-多單訊號" aria-label="Permalink to &quot;✅ 指標 3：尿素價格 + 多單訊號&quot;">​</a></h3><p><strong>狀態：已突破 🔴 觸發警報</strong></p><ul><li>4/10 基準尿素價格約 <strong>$694.25/噸</strong>（月增 17.32%，年增 75.32%）</li><li>4 月上半月：美國零售尿素高達 <strong>$826/噸</strong></li><li>4 月第 2 週：均價 <strong>$858/噸</strong>（月增 27%）</li><li>4 月第 3 週：均價 <strong>$866/噸</strong></li><li>World Bank 預測全球肥料價格 2026 年上漲超過 <strong>30%</strong></li><li>🚨 <strong>尿素多單訊號已觸發</strong> — 價格遠超 $700/閾值</li></ul><h3 id="✅-指標-4-荷莫茲海峽通航狀態" tabindex="-1">✅ 指標 4：荷莫茲海峽通航狀態 <a class="header-anchor" href="#✅-指標-4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;✅ 指標 4：荷莫茲海峽通航狀態&quot;">​</a></h3><p><strong>狀態：實質關閉 🔴 重大風險</strong></p><ul><li>4/30 僅 <strong>11 艘船</strong>通過（正常日均 60 艘，約 13.3%）</li><li>整體吞吐量僅正常水平的 <strong>12%</strong></li><li>4/8 暫停敵對行動後迅速重新封閉，和平談判停滯</li><li>US 尋求「Maritime Freedom Construct」國際聯盟（5/1 前提出）</li><li>全球約 20% 石油和 LNG 流量受影響，每日移除 1,200-1,300 萬桶</li></ul><h3 id="✅-指標-5-中美貿易-中國進口" tabindex="-1">✅ 指標 5：中美貿易 + 中國進口 <a class="header-anchor" href="#✅-指標-5-中美貿易-中國進口" aria-label="Permalink to &quot;✅ 指標 5：中美貿易 + 中國進口&quot;">​</a></h3><p><strong>狀態：有變化 🟡 部分改善</strong></p><ul><li>2/26 最高法院推翻 IEEPA 關稅 → 取消 10%「芬太尼關稅」和 10% 對等關稅</li><li>首批退款約 $1,660 億預計 5/11 開始發放</li><li>Trump 啟動 Section 122 全球關稅 10%（至 7/24 到期）</li><li>USTR 對 60 個經濟體舉行 Section 301 聽證會</li><li>中國 5/1 起對 53 個非洲國家出口零關稅（至 2028/4/30）</li><li>中國黃豆進口仍以南美為主（巴西 + 阿根廷占 80%）</li></ul><h3 id="✅-指標-6-天然氣價格" tabindex="-1">✅ 指標 6：天然氣價格 <a class="header-anchor" href="#✅-指標-6-天然氣價格" aria-label="Permalink to &quot;✅ 指標 6：天然氣價格&quot;">​</a></h3><p><strong>狀態：持續下降 🟢 相對利好</strong></p><ul><li>4/30 Henry Hub 天然氣降至 <strong>$2.64/MMBtu</strong>（日減 0.29%）</li><li>月減 <strong>8.48%</strong>，年減 <strong>24.13%</strong></li><li>4/2 觸及六個月低點 $2.82/MMBtu</li><li>Trading Economics 預測 Q2 末均價 <strong>$2.65/MMBtu</strong>，12 個月後 <strong>$3.28/MMBtu</strong></li><li>📉 天然氣下降 → 尿素成本壓力部分緩解（但海峽封閉抵消此優勢）</li></ul><h3 id="✅-指標-7-聖嬰-拉尼娜氣候風險" tabindex="-1">✅ 指標 7：聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#✅-指標-7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;✅ 指標 7：聖嬰/拉尼娜氣候風險&quot;">​</a></h3><p><strong>狀態：有重大變化 ⚠️ 轉換中</strong></p><ul><li>La Niña 減弱，目前 ENSO 中性（55%-80% 機率維持至 7 月）</li><li><strong>聖嬰可能於 5-7 月出現</strong>（機率 61%-62%）</li><li>部分模型顯示 10-12 月有 <strong>1/3 機率強聖嬰</strong>，冬季甚至 1/4 機率極強聖嬰</li><li>🚨 聖嬰可能導致巴西南部和阿根廷乾旱，影響黃豆產量</li></ul><h3 id="✅-指標-8-cbot-價格區間" tabindex="-1">✅ 指標 8：CBOT 價格區間 <a class="header-anchor" href="#✅-指標-8-cbot-價格區間" aria-label="Permalink to &quot;✅ 指標 8：CBOT 價格區間&quot;">​</a></h3><p><strong>狀態：介於兩者之間 🟡</strong></p><ul><li>CBOT 5 月合約（ZSK26）4/29 收盤價：<strong>$11.82¼ / 蒲式耳</strong>（約 <strong>1,182.25 美分</strong>）</li><li>4/24 收盤：1,163.75 美分 → 4/29 上漲 <strong>9¼ 美分</strong></li><li>第一通知日：4/30；到期日：<strong>5/14</strong></li><li>Q1 黃豆價格上漲近 <strong>12%</strong></li><li>目前介於 1,150-1,200 之間，<strong>尚未觸發任一邊界</strong></li></ul><hr><h2 id="📊-綜合評估" tabindex="-1">📊 綜合評估 <a class="header-anchor" href="#📊-綜合評估" aria-label="Permalink to &quot;📊 綜合評估&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">#</th><th style="text-align:left;">指標</th><th style="text-align:center;">狀態</th><th style="text-align:center;">影響方向</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">USDA 種植進度</td><td style="text-align:center;">⚠️ 快速超前（23% vs 5年均 12%）</td><td style="text-align:center;">利多（產量可能增加）</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">巴西供應/出口</td><td style="text-align:center;">⚠️ 創紀錄豐收</td><td style="text-align:center;">利空（供應充足）</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">尿素價格 + 多單</td><td style="text-align:center;">🔴 已突破（$866/噸 &gt;&gt; $700）</td><td style="text-align:center;">利空（種植成本上升）</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">荷莫茲海峽</td><td style="text-align:center;">🔴 實質關閉（僅 13.3% 流量）</td><td style="text-align:center;">利空（供應鏈中斷）</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;">中美貿易 + 進口</td><td style="text-align:center;">🟡 部分改善（關稅退款、Section 122）</td><td style="text-align:center;">中性偏多</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:left;">天然氣價格</td><td style="text-align:center;">🟢 持續下降（$2.64/MMBtu）</td><td style="text-align:center;">利多（成本壓力緩解）</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:left;">聖嬰/拉尼娜</td><td style="text-align:center;">⚠️ 轉換中（61% 機率聖嬰）</td><td style="text-align:center;">不確定（乾旱風險）</td></tr><tr><td style="text-align:center;">8</td><td style="text-align:left;">CBOT 價格區間</td><td style="text-align:center;">🟡 1,182 美分（未觸發邊界）</td><td style="text-align:center;">中性</td></tr></tbody></table><p><strong>多空平衡：偏空（供應充足 + 成本上升 vs 天然氣下降 + 關稅部分改善）</strong></p><hr><p><em>報告產出：Dr.32 知識管家 | 模型：local/Qwen3.6-35B-A3B-4bit</em></p>',34)])])}const x=e(a,[["render",i]]);export{u as __pageData,x as default};
